parameters.jsCode:
const subscribers = $input.first().json;
const html = $('Editorial Editor1').item.json.output;

return subscribers.map(sub => ({
  email: sub.users?.email || sub.email,
  name: sub.users?.name || 'Assinante',
  html: html
}));

const webhookBody = $('webhook - WEB').first().json.body;
const raw = $json.output || '{}';

let parsed;

try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = { results: [] };
}

const results = Array.isArray(parsed.results) ? parsed.results : [];

return [
  {
    json: {
      session_id: webhookBody.session_id,
      user_id: webhookBody.user_id,
      path: webhookBody.path,
      message: webhookBody.message,
      model_pref: webhookBody.model_pref || 'auto',
      is_followup: webhookBody.path === 'followup',
      results_count: results.length,
      results: results
    }
  }
];

const rawContext = $json.value;

let parsedContext = {};

try {
  parsedContext = typeof rawContext === 'string' ? JSON.parse(rawContext) : rawContext;
} catch (error) {
  parsedContext = {
    parse_error: true,
    raw_context: rawContext
  };
}

return [
  {
    json: {
      session_id: $json.session_id,
      user_id: $json.user_id,
      path: $json.path,
      message: $json.message,
      model_pref: $json.model_pref,
      is_followup: $json.is_followup,
      cache_key_response: $json.cache_key_response,
      cache_key_context: $json.cache_key_context,
      request_timestamp: $json.request_timestamp,

      followup_context_available: true,
      followup_context: parsedContext,
      last_path: parsedContext.last_path || '',
      last_user_message: parsedContext.last_user_message || '',
      last_editorial_response: parsedContext.last_editorial_response || '',
      last_search_results: parsedContext.last_search_results || []
    }
  }
];
